# ai_engine.pyfrom groq import Groqfrom dotenv import load_dotenvimport osload_dotenv()client = Groq(api_key=os.getenv("GROQ_API_KEY"))def generate_briefing(team_data: str) -> str:    prompt = f"""    You are an advanced AI Mission Control assistant designed to help managers     reduce information overload and make fast, intelligent decisions.    Analyse the following team data and produce the following sections:    EXECUTIVE SUMMARY:    TOP 3 URGENT ISSUES:    BURNOUT SIGNALS:    DEADLINE RISKS:    RECOMMENDED ACTIONS:    RETURN ALL SECTION HEADERS IN FULL UPPERCASE EXACTLY AS WRITTEN.    Team Data:    {team_data}    """    response = client.chat.completions.create(        model="llama-3.1-8b-instant",        messages=[            {"role": "system", "content": "You produce structured executive briefings."},            {"role": "user", "content": prompt}        ],        temperature=0.2    )    return response.choices[0].message.contentdef generate_trends(team_data: str) -> str:    prompt = f"""    Analyse the following team data and identify trends, repeated patterns,    changes over time, and emerging risks. Focus on workload, sentiment,    delays, burnout signals, and any patterns a manager should notice.    Return 3–6 bullet points only.    Team Data:    {team_data}    """    response = client.chat.completions.create(        model="llama-3.1-8b-instant",        messages=[            {"role": "system", "content": "You detect patterns and trends in team data."},            {"role": "user", "content": prompt}        ],        temperature=0.2    )    return response.choices[0].message.contentdef generate_risk_score(team_data: str) -> str:    prompt = f"""    You are calculating a numerical risk score.    Rules:    - Return ONLY a number from 0 to 100.    - No words.    - No symbols.    - No punctuation.    - No explanation.    - No markdown.    - No percentage sign.    - Just the number.    Team Data:    {team_data}    """    response = client.chat.completions.create(        model="llama-3.1-8b-instant",        messages=[            {"role": "system", "content": "You calculate risk scores."},            {"role": "user", "content": prompt}        ],        temperature=0    )    return response.choices[0].message.content.strip()def generate_deadline_pressure(team_data: str) -> str:    prompt = f"""    You MUST return a single integer from 0 to 100.    HARD RULES:    - No decimals    - No scientific notation    - No words    - No symbols    - No punctuation    - No explanation    - Only return digits 0–100    If unsure, return 50.    Team Data:    {team_data}    """    response = client.chat.completions.create(        model="llama-3.1-8b-instant",        messages=[            {"role": "system", "content": "Return only integers."},            {"role": "user", "content": prompt}        ],        temperature=0    )    return response.choices[0].message.content.strip()def generate_blindspots(team_data: str) -> str:    prompt = f"""    Analyse the following team data and identify hidden risks, blind spots,    or issues a manager might overlook. Focus on subtle patterns, indirect    signals, and second‑order effects.    Return 3–6 bullet points only.    Team Data:    {team_data}    """    response = client.chat.completions.create(        model="llama-3.1-8b-instant",        messages=[            {"role": "system", "content": "You detect blind spots and hidden risks."},            {"role": "user", "content": prompt}        ],        temperature=0.3    )    return response.choices[0].message.content